// 接口定义示例
struct ring_buffer {
    uint8_t *buffer;
    size_t head;
    size_t tail;
    size_t size;
};
// API 契约
int rb_init(struct ring_buffer *rb, uint8_t *buf, size_t size);
size_t rb_write(struct ring_buffer *rb, const uint8_t *data, size_t len);
size_t rb_read(struct ring_buffer *rb, uint8_t *data, size_t len);

/* 1. 配置 DMA 传输 */
HAL_UART_Receive_DMA(&huart1, dma_buffer, BUFFER_SIZE);

void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    // 2. 传输完成，处理下半区数据
    process_data(&dma_buffer[BUFFER_SIZE/2], BUFFER_SIZE/2);
}

void HAL_UART_RxHalfCpltCallback(UART_HandleTypeDef *huart) {
    // 3. 半传输完成，处理上半区数据
    process_data(&dma_buffer[0], BUFFER_SIZE/2);
}

// 4. 清除逻辑由 HAL_DMA_IRQHandler 自动处理，
// 需确保 NVIC_PriorityGroup 优先级配置高于耗时任务。

/* 常见的循环溢出错误 */
if (head == tail) { /* buffer full */ }
// 修正方法：使用 count 字段
if (rb->count == rb->size) { /* buffer full */ }

// 改进前 (坏味道)
uint8_t g_rx_buf[100];
int g_idx = 0;
void process() { g_rx_buf[g_idx++] = ... }

// 改进后
struct RingBuffer { uint8_t *buf; size_t head; size_t size; };
size_t rb_push(struct RingBuffer *rb, uint8_t val) {
    rb->buf[rb->head] = val;
    rb->head = (rb->head + 1) % rb->size;
    return 1;
}
